import{_ as a,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Modelo Purdue","description":"","frontmatter":{},"headers":[],"relativePath":"es/digitalization/purdue-model.md","filePath":"es/digitalization/purdue-model.md"}'),r={name:"es/digitalization/purdue-model.md"};function l(n,e,t,c,d,u){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="modelo-purdue" tabindex="-1">Modelo Purdue <a class="header-anchor" href="#modelo-purdue" aria-label="Permalink to &quot;Modelo Purdue&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El Modelo Purdue es una arquitectura de referencia utilizada para estructurar sistemas industriales en niveles jerárquicos.</p><p>Define cómo se organizan los sistemas desde los procesos físicos hasta los sistemas empresariales. Esta estructura ayuda a gestionar la comunicación, la seguridad y las responsabilidades del sistema.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito del Modelo Purdue es:</p><ul><li>Proporcionar una estructura clara para el diseño de sistemas industriales</li><li>Separar funciones según su rol y criticidad</li><li>Controlar el flujo de datos entre diferentes niveles del sistema</li><li>Soportar la integración segura entre sistemas OT e IT</li></ul><p>Ayuda a los ingenieros a diseñar sistemas más fáciles de gestionar y proteger.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>El Modelo Purdue divide los sistemas industriales en niveles, cada uno con una función específica.</p><h3 id="nivel-0-–-proceso-fisico" tabindex="-1">Nivel 0 – Proceso físico <a class="header-anchor" href="#nivel-0-–-proceso-fisico" aria-label="Permalink to &quot;Nivel 0 – Proceso físico&quot;">​</a></h3><ul><li>Sensores y actuadores</li><li>Interacción directa con el proceso físico</li></ul><h3 id="nivel-1-–-control-basico" tabindex="-1">Nivel 1 – Control básico <a class="header-anchor" href="#nivel-1-–-control-basico" aria-label="Permalink to &quot;Nivel 1 – Control básico&quot;">​</a></h3><ul><li>PLC y controladores locales</li><li>Control en tiempo real de los equipos</li></ul><h3 id="nivel-2-–-control-supervisado" tabindex="-1">Nivel 2 – Control supervisado <a class="header-anchor" href="#nivel-2-–-control-supervisado" aria-label="Permalink to &quot;Nivel 2 – Control supervisado&quot;">​</a></h3><ul><li>Sistemas HMI y SCADA</li><li>Monitoreo e interacción con operadores</li></ul><h3 id="nivel-3-–-gestion-de-operaciones" tabindex="-1">Nivel 3 – Gestión de operaciones <a class="header-anchor" href="#nivel-3-–-gestion-de-operaciones" aria-label="Permalink to &quot;Nivel 3 – Gestión de operaciones&quot;">​</a></h3><ul><li>Sistemas de gestión de producción</li><li>Agregación de datos y coordinación de operaciones</li></ul><h3 id="nivel-4-–-sistemas-empresariales" tabindex="-1">Nivel 4 – Sistemas empresariales <a class="header-anchor" href="#nivel-4-–-sistemas-empresariales" aria-label="Permalink to &quot;Nivel 4 – Sistemas empresariales&quot;">​</a></h3><ul><li>Sistemas de negocio como ERP</li><li>Planeación, analítica y procesos empresariales</li></ul><p>La comunicación normalmente fluye entre niveles adyacentes. La comunicación directa entre niveles no contiguos se limita para reducir complejidad y riesgos.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El Modelo Purdue se utiliza en:</p><ul><li>Diseño de arquitecturas de red industrial</li><li>Integración entre sistemas de control y sistemas empresariales</li><li>Planificación de ciberseguridad y segmentación</li><li>Estandarización de estructuras de sistemas entre instalaciones</li></ul><p>Es ampliamente aplicado en manufactura, energía e infraestructura.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>No todos los sistemas siguen estrictamente cada nivel</li><li>Las arquitecturas modernas pueden combinar u omitir niveles</li><li>Las conexiones directas entre niveles lejanos incrementan el riesgo</li><li>El modelo es una guía, no una regla estricta</li><li>La integración con tecnologías modernas debe gestionarse cuidadosamente</li></ul><p>El modelo debe adaptarse a las necesidades específicas de cada sistema.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Utilizar el modelo como punto de partida para estructurar sistemas</li><li>Definir claramente qué dispositivos pertenecen a cada nivel</li><li>Controlar la comunicación entre niveles mediante reglas definidas</li><li>Evitar conexiones innecesarias entre capas de control y empresariales</li><li>Mantener la documentación alineada con la arquitectura definida</li></ul><p>El Modelo Purdue proporciona un marco claro para organizar sistemas industriales y gestionar sus interacciones.</p>',31)])])}const h=a(r,[["render",l]]);export{m as __pageData,h as default};
